from flask import Flask, request, jsonify
import hmac
import hashlib

app = Flask(__name__)

# Secret key for HMAC validation
SECRET_KEY = b'your_secret_key_here'

# Function to validate the webhook signature
def validate_signature(request):
    signature = request.headers.get('X-Signature')
    if not signature:
        return False

    calculated_signature = hmac.new(SECRET_KEY, request.data, hashlib.sha256).hexdigest()
    return hmac.compare_digest(calculated_signature, signature)

# Cloud Function entry point
@app.route('/', methods=['POST'])
def webhook_handler():
    if request.method != 'POST':
        return jsonify({"error": "Invalid request method"}), 405
    
    # Validate the incoming request
    if not validate_signature(request):
        return jsonify({'error': 'Invalid signature'}), 400

    # Process the webhook payload
    payload = request.json
    # Example: Handle payment events
    if payload.get('event') == 'payment_received':
        # Process the payment
        print(f"Payment received: {payload}")

    # Respond to the webhook
    return jsonify({'status': 'success'}), 200

